import React, { useState, useEffect } from 'react';
import { adminService } from '../services/api';
import { LayoutDashboard, Package, ShoppingCart, DollarSign, Users } from 'lucide-react';

function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    try {
      const response = await adminService.getDashboard();
      setStats(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error loading dashboard:', error);
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0
    }).format(amount);
  };

  if (loading) {
    return <div style={{ padding: '2rem' }}>Loading...</div>;
  }

  return (
    <div style={{ padding: '2rem' }}>
      <h1 style={{ marginBottom: '2rem', fontSize: '2rem', fontWeight: '700' }}>Admin Dashboard</h1>

      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
        gap: '1.5rem',
        marginBottom: '2rem'
      }}>
        {/* Total Products Card */}
        <div style={{
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          padding: '1.5rem',
          borderRadius: '12px',
          color: 'white',
          boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div>
              <p style={{ fontSize: '0.875rem', opacity: 0.9 }}>Total Products</p>
              <p style={{ fontSize: '2rem', fontWeight: '700', marginTop: '0.5rem' }}>
                {stats?.totalProducts || 0}
              </p>
            </div>
            <Package size={32} style={{ opacity: 0.8 }} />
          </div>
        </div>

        {/* Total Sales Card */}
        <div style={{
          background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
          padding: '1.5rem',
          borderRadius: '12px',
          color: 'white',
          boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div>
              <p style={{ fontSize: '0.875rem', opacity: 0.9 }}>Total Sales</p>
              <p style={{ fontSize: '2rem', fontWeight: '700', marginTop: '0.5rem' }}>
                {stats?.totalSales || 0}
              </p>
            </div>
            <ShoppingCart size={32} style={{ opacity: 0.8 }} />
          </div>
        </div>

        {/* Total Revenue Card */}
        <div style={{
          background: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
          padding: '1.5rem',
          borderRadius: '12px',
          color: 'white',
          boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div>
              <p style={{ fontSize: '0.875rem', opacity: 0.9 }}>Total Revenue</p>
              <p style={{ fontSize: '1.5rem', fontWeight: '700', marginTop: '0.5rem' }}>
                {formatCurrency(stats?.totalRevenue || 0)}
              </p>
            </div>
            <DollarSign size={32} style={{ opacity: 0.8 }} />
          </div>
        </div>

        {/* Commission Paid Card */}
        <div style={{
          background: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)',
          padding: '1.5rem',
          borderRadius: '12px',
          color: 'white',
          boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div>
              <p style={{ fontSize: '0.875rem', opacity: 0.9 }}>Commission Paid</p>
              <p style={{ fontSize: '1.5rem', fontWeight: '700', marginTop: '0.5rem' }}>
                {formatCurrency(stats?.totalCommissionPaid || 0)}
              </p>
            </div>
            <DollarSign size={32} style={{ opacity: 0.8 }} />
          </div>
        </div>

        {/* Active Partners Card */}
        <div style={{
          background: 'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
          padding: '1.5rem',
          borderRadius: '12px',
          color: 'white',
          boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div>
              <p style={{ fontSize: '0.875rem', opacity: 0.9 }}>Active Partners</p>
              <p style={{ fontSize: '2rem', fontWeight: '700', marginTop: '0.5rem' }}>
                {stats?.activePartners || 0}
              </p>
            </div>
            <Users size={32} style={{ opacity: 0.8 }} />
          </div>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
